package main

import "fmt"

func main() {
    // Different make forms
    s1 := make([]int, 3)      // [0, 0, 0]
    s2 := make([]int, 2, 5)   // [0, 0] with cap=5

    fmt.Println("s1:", s1, "len:", len(s1), "cap:", cap(s1))
    fmt.Println("s2:", s2, "len:", len(s2), "cap:", cap(s2))

    // Build with pre-allocated capacity
    s3 := make([]int, 0, 5)
    for i := 1; i <= 5; i++ {
        s3 = append(s3, i*10)
    }
    fmt.Println("s3:", s3, "len:", len(s3), "cap:", cap(s3))

    // Map with make
    m := make(map[string]int, 10)
    m["key"] = 42
    fmt.Println("map:", m)
}
